-- 1. DRIVER CREATE TABLE driver ( id VARCHAR(26) PRIMARY KEY, trophies INTEGER NOT NULL );
-- 2. TRACK CREATE TABLE track ( id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, track_name VARCHAR(150) NOT NULL, country VARCHAR(3), city TEXT NOT NULL, track_length INTEGER NOT NULL, racing_approved BOOLEAN NOT NULL, date_created TIMESTAMPTZ NOT NULL, date_updated TIMESTAMPTZ NOT NULL );
-- 3. LAP CREATE TABLE lap ( id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, driver_id VARCHAR(26) NOT NULL, track_id BIGINT NOT NULL, car_id BIGINT NOT NULL, lap_date TIMESTAMPTZ NOT NULL, lap_time NUMERIC(9, 6) NOT NULL, special_tires BOOLEAN NOT NULL, lap_approved BOOLEAN, comments VARCHAR(500), admin_comments VARCHAR(500), highest_recorded_speed INTEGER, date_created TIMESTAMPTZ NOT NULL, date_updated TIMESTAMPTZ NOT NULL,
CONSTRAINT fk_lap__driver FOREIGN KEY (driver_id) REFERENCES driver (id),
CONSTRAINT fk_lap__track FOREIGN KEY (track_id) REFERENCES track (id),
CONSTRAINT fk_lap__car_spec FOREIGN KEY (car_id) REFERENCES car_specifications (id) );

